/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWVeiculos-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&VeiPla.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Placa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiPla) EndIf
If not (&VeiCha.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Chassi") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiCha) EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'VEIMOD' &VeiMod1.FromString(&GridStateDynamicFilter.Value) If not &VeiMod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Modelo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMod1) EndIf Case &DynamicFiltersSelector1 = !'VEIUFENOM' &VeiUfeNom1.FromString(&GridStateDynamicFilter.Value) If not &VeiUfeNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Estado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiUfeNom1) EndIf Case &DynamicFiltersSelector1 = !'VEIMARNOM' &VeiMarNom1.FromString(&GridStateDynamicFilter.Value) If not &VeiMarNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Marca" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMarNom1) EndIf Case &DynamicFiltersSelector1 = !'CORNOM' &CorNom1.FromString(&GridStateDynamicFilter.Value) If not &CorNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CorNom1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'VEIMOD' &VeiMod2.FromString(&GridStateDynamicFilter.Value) If not &VeiMod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Modelo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMod2) EndIf Case &DynamicFiltersSelector2 = !'VEIUFENOM' &VeiUfeNom2.FromString(&GridStateDynamicFilter.Value) If not &VeiUfeNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Estado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiUfeNom2) EndIf Case &DynamicFiltersSelector2 = !'VEIMARNOM' &VeiMarNom2.FromString(&GridStateDynamicFilter.Value) If not &VeiMarNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Marca" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMarNom2) EndIf Case &DynamicFiltersSelector2 = !'CORNOM' &CorNom2.FromString(&GridStateDynamicFilter.Value) If not &CorNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CorNom2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'VEIMOD' &VeiMod3.FromString(&GridStateDynamicFilter.Value) If not &VeiMod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Modelo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMod3) EndIf Case &DynamicFiltersSelector3 = !'VEIUFENOM' &VeiUfeNom3.FromString(&GridStateDynamicFilter.Value) If not &VeiUfeNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Estado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiUfeNom3) EndIf Case &DynamicFiltersSelector3 = !'VEIMARNOM' &VeiMarNom3.FromString(&GridStateDynamicFilter.Value) If not &VeiMarNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Marca" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&VeiMarNom3) EndIf Case &DynamicFiltersSelector3 = !'CORNOM' &CorNom3.FromString(&GridStateDynamicFilter.Value) If not &CorNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CorNom3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Placa" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Modelo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "UF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Marca" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Cor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Modelo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Rodado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Carroceria" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Proprietário" &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "E-Frete"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod VeiPla when &OrderedBy = 1 order VeiMod when &OrderedBy = 2 AND &OrderedDsc = False order (VeiMod) when &OrderedBy = 2 AND &OrderedDsc = True order VeiUfeCod when &OrderedBy = 3 AND &OrderedDsc = False order (VeiUfeCod) when &OrderedBy = 3 AND &OrderedDsc = True order VeiMarNom when &OrderedBy = 4 AND &OrderedDsc = False order (VeiMarNom) when &OrderedBy = 4 AND &OrderedDsc = True order CorNom when &OrderedBy = 5 AND &OrderedDsc = False order (CorNom) when &OrderedBy = 5 AND &OrderedDsc = True order VeiAnoMod when &OrderedBy = 6 AND &OrderedDsc = False order (VeiAnoMod) when &OrderedBy = 6 AND &OrderedDsc = True order VeiTip when &OrderedBy = 7 AND &OrderedDsc = False order (VeiTip) when &OrderedBy = 7 AND &OrderedDsc = True order VeiTipRod when &OrderedBy = 8 AND &OrderedDsc = False order (VeiTipRod) when &OrderedBy = 8 AND &OrderedDsc = True order VeiTipCarr when &OrderedBy = 9 AND &OrderedDsc = False order (VeiTipCarr) when &OrderedBy = 9 AND &OrderedDsc = True order VeiProRaz when &OrderedBy = 10 AND &OrderedDsc = False order (VeiProRaz) when &OrderedBy = 10 AND &OrderedDsc = True order VeiStsEfr when &OrderedBy = 11 AND &OrderedDsc = False order (VeiStsEfr) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWVeiculos(&VeiPla, &VeiCha, &DynamicFiltersSelector1, &VeiMod1, &VeiUfeNom1, &VeiMarNom1 , &CorNom1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &VeiMod2, &VeiUfeNom2, &VeiMarNom2 , &CorNom2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &VeiMod3, &VeiUfeNom3, &VeiMarNom3 , &CorNom3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' if VeiPla.IsEmpty() or VeiPla.IsNull() &placa = '-'+trim(str(VeiCod)) Else &placa = VeiPla Endif &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(&placa) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(VeiMod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(VeiUfeCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(VeiMarNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(CorNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = VeiAnoMod &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = VeiTip.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = VeiTipRod.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = VeiTipCarr.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = WWP_Export_SecureText(VeiProRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = VeiStsEfr.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWVeiculosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWVeiculosGridState")) Else &GridState.FromXml(&Session.Get(!"WWVeiculosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"VEIPLA" &VeiPla.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"VEICHA" &VeiCha.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

